#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N;
        scanf("%lld", &N);
        long long free = N / 5;
        long long coins = N - free;
        printf("%lld\n", coins);
    }
    return 0;
}

