#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        n = int(data[i])
        coins = n - n//5
        out.append(str(coins))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

